import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

/** Minimal valid 1x1 JPEG bytes for multipart upload tests. */
const MINI_JPEG = Buffer.from(
  '',
  'base64',
)

export const FIXTURE_JPEG_PATH = path.join(__dirname, 'sample.jpg')

export function ensureFixtureJpeg(): string {
  if (!fs.existsSync(FIXTURE_JPEG_PATH)) {
    fs.writeFileSync(FIXTURE_JPEG_PATH, MINI_JPEG)
  }
  return FIXTURE_JPEG_PATH
}
